import 'dart:io';import 'package:flutter_test/flutter_test.dart';import 'package:oraculo_ia/src/features/editorial/domain/editorial_status.dart';void main(){test('manifest has complete metadata',(){final items=const EditorialManifestReader().parse(File('knowledge/editorial_manifest_v1.json').readAsStringSync(),now:DateTime(2026,7,12));expect(items,hasLength(5));expect(items.every((i)=>i.sources.isNotEmpty),isTrue);});test('rejects textual quote without source',(){const bad='{"schemaVersion":1,"items":[{"id":"x","title":"x","author":"x","version":"1","created":"2026-01-01","reviewed":"2026-01-01","status":"revisado","sources":["x"],"notes":"x","nextReview":"2027-01-01","currentClaims":false,"textualQuotes":[{"text":"x"}]}]}';expect(()=>const EditorialManifestReader().parse(bad),throwsFormatException);});}
